static void component_host_c64_handler_video_frame(CPUState *cpu, const uint64_t *args, uint8_t argc) {
    (void)argc;
    ComponentState_host_c64 *comp = &cpu->comp_host_c64;
    cpu->active_component_id = "host_c64";
    if (argc >= 4u) {
        uint32_t *picker_pixels = (uint32_t *)(uintptr_t)args[1];
        uint32_t picker_w = (uint32_t)(args[2] & 0xFFFFFFFFu);
        uint32_t picker_h = (uint32_t)(args[3] & 0xFFFFFFFFu);
        cpu_component_cartridge_picker_draw_overlay(cpu, picker_pixels, picker_w, picker_h);
    }
    if (comp->host_inited == 0u || argc < 4) return;
    void *renderer = comp->renderer;
    void *texture = comp->texture;
    uint32_t frame = (uint32_t)(args[0] & 0xFFFFFFFFu);
    uint32_t *pixels = (uint32_t *)(uintptr_t)args[1];
    uint32_t w = (uint32_t)(args[2] & 0xFFFFFFFFu);
    uint32_t h = (uint32_t)(args[3] & 0xFFFFFFFFu);
    if (renderer == NULL || texture == NULL || pixels == NULL || w == 0u || h == 0u) return;
    comp->frame_count = frame;
    if (cpu->debug_overlay_enabled) {
        sms_overlay_draw_perf(
            pixels,
            w,
            h,
            comp->overlay_fps_x100,
            comp->overlay_cpu_hz,
            comp->overlay_cpu_pct_x10
        );
    }
    if (comp->texture_w != w || comp->texture_h != h) {
        cpu_host_hal_destroy_texture(texture);
        texture = cpu_host_hal_create_texture(renderer, CPU_HOST_PIXELFORMAT_ARGB8888, CPU_HOST_TEXTUREACCESS_STREAMING, (int)w, (int)h);
        if (texture == NULL) return;
        comp->texture = (void *)texture;
        comp->texture_w = w;
        comp->texture_h = h;
    }
    if (cpu_host_hal_update_texture(texture, NULL, pixels, (int)(w * sizeof(uint32_t))) != 0) return;
    cpu_host_hal_render_set_draw_color(renderer, 0, 0, 0, 255);
    cpu_host_hal_render_clear(renderer);
    {
        int ww = 0;
        int wh = 0;
        CPUHostRect dst;
        int scaled_w = 0;
        int scaled_h = 0;
        if (cpu_host_hal_renderer_output_size(renderer, &ww, &wh) != 0 || ww <= 0 || wh <= 0) return;
        scaled_w = ww;
        scaled_h = (int)((((int64_t)ww) * (int64_t)h) / (int64_t)w);
        if (scaled_h > wh) {
            scaled_h = wh;
            scaled_w = (int)((((int64_t)wh) * (int64_t)w) / (int64_t)h);
        }
        dst.w = (scaled_w > 0) ? scaled_w : ww;
        dst.h = (scaled_h > 0) ? scaled_h : wh;
        dst.x = (ww - dst.w) / 2;
        dst.y = (wh - dst.h) / 2;
        if (cpu_host_hal_render_copy(renderer, texture, NULL, &dst) != 0) return;
    }
    cpu_host_hal_render_present(renderer);
}

static void component_host_c64_handler_audio_pcm(CPUState *cpu, const uint64_t *args, uint8_t argc) {
    (void)argc;
    ComponentState_host_c64 *comp = &cpu->comp_host_c64;
    cpu->active_component_id = "host_c64";
    if (argc == 0) return;
    {
        uint8_t level8 = (uint8_t)(args[0] & 0xFFu);
        uint64_t src_cycle = (argc > 1) ? args[1] : cpu->total_cycles;
        int16_t cur = (int16_t)(((int16_t)(int)level8 - 128) << 8);
        int16_t prev = comp->audio_level;
        uint32_t rate = (comp->audio_rate > 0u) ? comp->audio_rate : ((CPU_AUDIO_SAMPLE_RATE > 0u) ? CPU_AUDIO_SAMPLE_RATE : 44100u);
        uint64_t hz = (CPU_SYSTEM_CLOCK_HZ > 0u) ? CPU_SYSTEM_CLOCK_HZ : 1u;
        uint64_t target_sample = (src_cycle * (uint64_t)rate) / hz;

        comp->audio_last_cycle = src_cycle;
        if (comp->audio_sample_cursor == 0u) comp->audio_sample_cursor = target_sample;

        if (comp->audio_ring != NULL && comp->audio_ring_capacity > 0u) {
            if (target_sample > comp->audio_sample_cursor) {
                uint64_t gap = target_sample - comp->audio_sample_cursor;
                while (gap > 0u) {
                    uint64_t n = (gap > 4096u) ? 4096u : gap;
                    for (uint64_t i = 0u; i < n; ++i) {
                        if (comp->audio_ring_fill >= comp->audio_ring_capacity) {
                            comp->audio_ring_read_idx += 1u;
                            if (comp->audio_ring_read_idx >= comp->audio_ring_capacity) comp->audio_ring_read_idx = 0u;
                            comp->audio_ring_fill -= 1u;
                        }
                        comp->audio_ring[comp->audio_ring_write_idx] = prev;
                        comp->audio_ring_write_idx += 1u;
                        if (comp->audio_ring_write_idx >= comp->audio_ring_capacity) comp->audio_ring_write_idx = 0u;
                        comp->audio_ring_fill += 1u;
                    }
                    comp->audio_sample_cursor += n;
                    gap -= n;
                }
            }

            if (comp->audio_ring_fill >= comp->audio_ring_capacity) {
                comp->audio_ring_read_idx += 1u;
                if (comp->audio_ring_read_idx >= comp->audio_ring_capacity) comp->audio_ring_read_idx = 0u;
                comp->audio_ring_fill -= 1u;
            }
            comp->audio_ring[comp->audio_ring_write_idx] = cur;
            comp->audio_ring_write_idx += 1u;
            if (comp->audio_ring_write_idx >= comp->audio_ring_capacity) comp->audio_ring_write_idx = 0u;
            comp->audio_ring_fill += 1u;
        }

        comp->audio_level = cur;
        if (target_sample >= comp->audio_sample_cursor) comp->audio_sample_cursor = target_sample + 1u;
    }
}

static void cpu_component_dispatch_handler(
    CPUState *cpu,
    const char *component_id,
    const char *handler_name,
    const uint64_t *args,
    uint8_t argc
) {
    if (strcmp(component_id, "video_c64") == 0 && strcmp(handler_name, "on_frame_ready") == 0) { component_video_c64_handler_on_frame_ready(cpu, args, argc); return; }
    if (strcmp(component_id, "speaker_c64") == 0 && strcmp(handler_name, "on_audio_level") == 0) { component_speaker_c64_handler_on_audio_level(cpu, args, argc); return; }
    if (strcmp(component_id, "host_c64") == 0 && strcmp(handler_name, "video_frame") == 0) { component_host_c64_handler_video_frame(cpu, args, argc); return; }
    if (strcmp(component_id, "host_c64") == 0 && strcmp(handler_name, "audio_pcm") == 0) { component_host_c64_handler_audio_pcm(cpu, args, argc); return; }
    (void)cpu;
    (void)component_id;
    (void)handler_name;
    (void)args;
    (void)argc;
}

static uint64_t cpu_component_call(
    CPUState *cpu,
    const char *source_component,
    const char *callback_name,
    const uint64_t *args,
    uint8_t argc
) {
    size_t connection_count = sizeof(g_component_connections) / sizeof(g_component_connections[0]);
    for (size_t i = 0; i < connection_count; i++) {
        const ComponentConnection *conn = &g_component_connections[i];
        if (strcmp(conn->from_component, source_component) != 0) continue;
        if (strcmp(conn->from_kind, "callback") != 0) continue;
        if (strcmp(conn->from_name, callback_name) != 0) continue;
        return cpu_component_dispatch_callback(cpu, conn->to_component, conn->to_name, args, argc);
    }
    return 0;
}

static void cpu_component_emit_signal(
    CPUState *cpu,
    const char *source_component,
    const char *signal_name,
    const uint64_t *args,
    uint8_t argc
) {
    size_t connection_count = sizeof(g_component_connections) / sizeof(g_component_connections[0]);
    for (size_t i = 0; i < connection_count; i++) {
        const ComponentConnection *conn = &g_component_connections[i];
        if (strcmp(conn->from_component, source_component) != 0) continue;
        if (strcmp(conn->from_kind, "signal") != 0) continue;
        if (strcmp(conn->from_name, signal_name) != 0) continue;
        cpu_component_dispatch_handler(cpu, conn->to_component, conn->to_name, args, argc);
    }
}

