    uint8_t y_before = cpu->registers[REG_Y];
    uint8_t c_before = cpu->flags.C ? 1u : 0u;
    uint8_t z_before = cpu->flags.Z ? 1u : 0u;
    uint8_t n_before = cpu->flags.N ? 1u : 0u;
    uint8_t v_before = cpu->flags.V ? 1u : 0u;

